;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="To become a <p>Pirate<w>!<r>Alignment:<y> Bad, Evil<r>Str: 12 Vit: 12 Luck: 10<w>"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("maxLife", 5)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP permanently increased by 5!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger
*event_4
;[exp] onObjectTrigger

@barrel anime=*barrel_poison
@eval exp='game.curTarget.heat += 10'
@eval exp='game.curTarget.setStatus(o.酩酊, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> got drunk!"'

[eventoff]
;===============================================================================
